import 'package:flutter/material.dart';import 'package:provider/provider.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_card.dart';import '../../design_system/ds_list_item.dart';import '../../providers/insights_provider.dart';import '../../services/mock_data_service.dart';class SubscriptionsRecurringPaymentsScreen extends StatelessWidget {  const SubscriptionsRecurringPaymentsScreen({super.key});  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text('Subscriptions & Recurring Payments', style: AppTypography.h2),      ),      body: Consumer<InsightsProvider>(        builder: (context, insightsProvider, child) {          return RefreshIndicator(            onRefresh: () async {              insightsProvider._loadInsightsData();            },            color: AppColors.primary,            backgroundColor: AppColors.surface,            child: ListView(              padding: AppSpacing.screenPadding,              children: [                DsPrimaryButton(                  text: 'Add Manual Recurring Payment',                  onPressed: () {                    ScaffoldMessenger.of(context).showSnackBar(                      const SnackBar(                          content: Text('Add Manual Recurring Payment coming soon!')),                    );                  },                ),                SizedBox(height: AppSpacing.paddingLarge),                Text('Upcoming Payments', style: AppTypography.h2),                SizedBox(height: AppSpacing.paddingMedium),                if (insightsProvider.recurringPayments.isEmpty)                  DsCard(                    child: Text(                      'No recurring payments found.',                      style: AppTypography.body.copyWith(color: AppColors.textSecondary),                    ),                  )                else                  DsCard(                    padding: EdgeInsets.zero,                    child: Column(                      children: insightsProvider.recurringPayments.map((payment) {                        return DsListItem(                          leading: Container(                            width: AppSpacing.categoryIconSize,                            height: AppSpacing.categoryIconSize,                            decoration: BoxDecoration(                              color: AppColors.primary.withOpacity(0.1),                              borderRadius:                                  BorderRadius.circular(AppSpacing.borderRadiusSmall),                            ),                            child: Icon(Icons.refresh, color: AppColors.primary),                          ),                          title: payment.name,                          subtitle:                            '${payment.frequency} • Next: ${payment.nextDueDate.day}/${payment.nextDueDate.month}',                          trailingText: MockDataService.formatCurrency(payment.amount),                          trailingTextColor: AppColors.error,                          onTap: () {                            ScaffoldMessenger.of(context).showSnackBar(                              SnackBar(content: Text('Viewing ${payment.name} details')),                            );                          },                        );                      }).toList(),                    ),                  ),              ],            ),          );        },      ),    );  }}